import React from 'react';
import './App.css';

function App() {
  return (
    <div>
      <ul>
        <li><a href="/home">Home</a></li>
        <li><a href="/products">Products</a></li>
        <li><a href="/about">About</a></li>
      </ul>
    </div>
  );
}

export default App;
